import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # state: (left_ext, right_ext), minimize left_ext + right_ext
    # For each left_ext, keep min right_ext
    dp = {0: 0}  # after first segment (both directions give same state)

    for i in range(1, n):
        d = a[i]
        ndp = {}
        for l, r in dp.items():
            # go right
            nl, nr = l + d, max(r - d, 0)
            if nl not in ndp or ndp[nl] > nr:
                ndp[nl] = nr
            # go left
            nl, nr = max(l - d, 0), r + d
            if nl not in ndp or ndp[nl] > nr:
                ndp[nl] = nr
        dp = ndp

    return min(l + r for l, r in dp.items())

t = int(input())
for _ in range(t):
    print(solve())

